for (const item of $input.all()) {
  // Kiểm tra xem payload gửi lên có chứa hình ảnh không
  if (item.json.body && item.json.body.image_base64) {
    // Tạo một tệp nhị phân (binary) tên là 'data' từ chuỗi base64
    item.binary = {
      data: {
        data: item.json.body.image_base64,
        mimeType: 'image/jpeg',
        fileName: 'bill.jpg'
      }
    };
  }
}
return $input.all();
